SELECT CAST(bimbo1.demandauniequil AS BIGINT) AS demandauniequil,   CAST(bimbo1.ventaunihoy AS BIGINT) AS ventaunihoy FROM bimbo1 WHERE (CAST(bimbo1.agenciaid AS BIGINT) IN (1110, 1111, 1112, 1113, 1114, 1116, 1117, 1118, 1119, 1120, 1121, 1122, 1123, 1124, 1126, 1127, 1129, 1130, 1137, 1138)) GROUP BY bimbo1.demandauniequil,   bimbo1.ventaunihoy,   demandauniequil,   bimbo1.ventaunihoy;
